1	export type QuestionType =
2	  | 'single_choice'
3	  | 'multi_choice'
4	  | 'numeric'
5	  | 'text'
6	  | 'true_false'
7	  | 'fill_in_blank';
8	
9	export type QuestionStatus = 'active' | 'inactive' | 'deleted';
10	
11	export interface QuestionChoice {
12	  id: string;
13	  label: string;
14	}
15	
16	export interface Question {
17	  id: string;
18	  type: QuestionType;
19	  prompt: string;
20	  // single/multi/true_false:
21	  choices: QuestionChoice[];
22	  correctChoiceIds: string[];
23	  // numeric:
24	  correctNumeric: number | null;
25	  numericTolerance: number;
26	  // fill_in_blank:
27	  acceptedAnswers: string[];
28	  caseSensitive: boolean;
29	  difficulty: 1 | 2 | 3 | 4 | 5;
30	  maxScore: number;
31	  explanation: string;
32	  tags: string[];
33	  knowledgePoints: string[];
34	  applicableDepartments: string[];
35	  status: QuestionStatus;
36	  createdAt: number;
37	  updatedAt: number;
38	  deletedAt: number | null;
39	}
40	
41	export type NewQuestionInput = Omit<Question, 'id' | 'status' | 'createdAt' | 'updatedAt' | 'deletedAt'>;
42	export type QuestionPatch = Partial<NewQuestionInput>;
43	
44	/** Stable choice ids for true/false questions, used everywhere they appear. */
45	export const TRUE_FALSE_CHOICES: QuestionChoice[] = [
46	  { id: 'true', label: 'True' },
47	  { id: 'false', label: 'False' }
48	];
