1	import type { NewQuestionInput, Question, QuestionPatch, QuestionType } from './question';
2	import { TRUE_FALSE_CHOICES } from './question';
3	
4	export interface QuestionLimits {
5	  minDifficulty: number;
6	  maxDifficulty: number;
7	  minScore: number;
8	  maxScore: number;
9	}
10	
11	export function validateQuestion(input: NewQuestionInput, limits: QuestionLimits): { ok: true } | { ok: false; errors: string[] } {
12	  const errors: string[] = [];
13	  if (!input.prompt || !input.prompt.trim()) errors.push('Prompt is required');
14	  if (input.difficulty < limits.minDifficulty || input.difficulty > limits.maxDifficulty) {
15	    errors.push(`Difficulty must be ${limits.minDifficulty}-${limits.maxDifficulty}`);
16	  }
17	  if (input.maxScore < limits.minScore || input.maxScore > limits.maxScore) {
18	    errors.push(`Score must be ${limits.minScore}-${limits.maxScore}`);
19	  }
20	  if (input.type === 'single_choice' || input.type === 'multi_choice') {
21	    if (input.choices.length < 2) errors.push('Provide at least two choices');
22	    if (input.correctChoiceIds.length === 0) errors.push('Mark at least one correct choice');
23	    if (input.type === 'single_choice' && input.correctChoiceIds.length !== 1) {
24	      errors.push('Single choice must have exactly one correct answer');
25	    }
26	    const ids = new Set(input.choices.map((c) => c.id));
27	    if (input.correctChoiceIds.some((c) => !ids.has(c))) errors.push('Correct ids must reference choices');
28	  }
29	  if (input.type === 'true_false') {
30	    if (input.choices.length !== 2 || input.choices[0].id !== 'true' || input.choices[1].id !== 'false') {
31	      errors.push('True/false questions must use the canonical true/false choice ids');
32	    }
33	    if (input.correctChoiceIds.length !== 1 || (input.correctChoiceIds[0] !== 'true' && input.correctChoiceIds[0] !== 'false')) {
34	      errors.push('True/false questions need exactly one correct answer (true or false)');
35	    }
36	  }
37	  if (input.type === 'numeric') {
38	    if (input.correctNumeric === null || !Number.isFinite(input.correctNumeric)) {
39	      errors.push('Numeric questions need a correct value');
40	    }
41	    if (!Number.isFinite(input.numericTolerance) || input.numericTolerance < 0) {
42	      errors.push('Numeric tolerance must be ≥ 0');
43	    }
44	  }
45	  if (input.type === 'fill_in_blank') {
46	    if (!input.acceptedAnswers || input.acceptedAnswers.length === 0) {
47	      errors.push('Fill-in-the-blank requires at least one accepted answer');
48	    } else if (input.acceptedAnswers.some((a) => !a.trim())) {
49	      errors.push('Accepted answers must be non-empty');
50	    }
51	  }
52	  return errors.length === 0 ? { ok: true } : { ok: false, errors };
53	}
54	
55	/** Build a fresh true_false question template with canonical choices. */
56	export function trueFalseTemplate(): Pick<NewQuestionInput, 'type' | 'choices' | 'correctChoiceIds'> {
57	  return {
58	    type: 'true_false',
59	    choices: TRUE_FALSE_CHOICES.map((c) => ({ ...c })),
60	    correctChoiceIds: ['true']
61	  };
62	}
63	
64	export function isObjective(type: QuestionType): boolean {
65	  return type !== 'text';
66	}
67	
68	export function applyPatch(existing: Question, patch: QuestionPatch): Question {
69	  return { ...existing, ...patch, id: existing.id, updatedAt: Date.now() };
70	}
71	
72	export function copy(existing: Question, newId: string): Question {
73	  const now = Date.now();
74	  return {
75	    ...existing,
76	    id: newId,
77	    prompt: `${existing.prompt} (copy)`,
78	    status: 'active',
79	    createdAt: now,
80	    updatedAt: now,
81	    deletedAt: null
82	  };
83	}
84	
85	export function deactivate(q: Question): Question {
86	  return { ...q, status: 'inactive', updatedAt: Date.now() };
87	}
88	
89	export function activate(q: Question): Question {
90	  return { ...q, status: 'active', updatedAt: Date.now() };
91	}
92	
93	export function softDelete(q: Question): Question {
94	  return { ...q, status: 'deleted', deletedAt: Date.now(), updatedAt: Date.now() };
95	}
96	
97	export function restore(q: Question): Question {
98	  return { ...q, status: 'inactive', deletedAt: null, updatedAt: Date.now() };
99	}
100	
