1	import type { Question, QuestionType } from '@domain/questions/question';
2	
3	/** Every question type the scoring pipeline knows how to handle. */
4	export const ALL_QUESTION_TYPES: readonly QuestionType[] = [
5	  'single_choice', 'multi_choice', 'numeric', 'text', 'true_false', 'fill_in_blank'
6	];
7	
8	/**
9	 * Validate that a weights map covers every question type. Throws on the
10	 * first missing key — used by the business config loader to fail fast
11	 * rather than relying on silent fallbacks downstream.
12	 */
13	export function validateWeights(weights: Record<string, number>): void {
14	  for (const t of ALL_QUESTION_TYPES) {
15	    if (typeof weights[t] !== 'number' || !Number.isFinite(weights[t])) {
16	      throw new Error(`Missing or invalid weight for question type '${t}'`);
17	    }
18	  }
19	}
20	
21	export interface AttemptAnswer {
22	  questionId: string;
23	  selectedChoiceIds?: string[];
24	  numericAnswer?: number;
25	  textAnswer?: string;
26	  fillAnswer?: string;
27	}
28	
29	function normalize(s: string, caseSensitive: boolean): string {
30	  const trimmed = s.trim();
31	  return caseSensitive ? trimmed : trimmed.toLowerCase();
32	}
33	
34	export interface AutoScoreResult {
35	  questionId: string;
36	  rawScore: number;        // 0..maxScore
37	  isCorrect: boolean;
38	  manualReviewRequired: boolean;
39	}
40	
41	export function autoScore(question: Question, answer: AttemptAnswer): AutoScoreResult {
42	  const max = question.maxScore;
43	  switch (question.type) {
44	    case 'single_choice':
45	    case 'true_false': {
46	      const selected = answer.selectedChoiceIds ?? [];
47	      const correct = selected.length === 1 && question.correctChoiceIds.includes(selected[0]);
48	      return { questionId: question.id, rawScore: correct ? max : 0, isCorrect: correct, manualReviewRequired: false };
49	    }
50	    case 'fill_in_blank': {
51	      const supplied = answer.fillAnswer;
52	      if (typeof supplied !== 'string' || supplied.trim().length === 0) {
53	        return { questionId: question.id, rawScore: 0, isCorrect: false, manualReviewRequired: false };
54	      }
55	      const candidate = normalize(supplied, question.caseSensitive);
56	      const accepted = question.acceptedAnswers.map((a) => normalize(a, question.caseSensitive));
57	      const hit = accepted.includes(candidate);
58	      return { questionId: question.id, rawScore: hit ? max : 0, isCorrect: hit, manualReviewRequired: false };
59	    }
60	    case 'multi_choice': {
61	      const selected = new Set(answer.selectedChoiceIds ?? []);
62	      const correct = new Set(question.correctChoiceIds);
63	      // Partial credit: fraction of correct picked minus penalty for wrong picks, clamped.
64	      let hits = 0; let wrong = 0;
65	      for (const id of selected) (correct.has(id) ? hits++ : wrong++);
66	      const total = correct.size;
67	      const ratio = Math.max(0, (hits - wrong) / total);
68	      const raw = roundToIncrement(ratio * max, 0.5);
69	      return { questionId: question.id, rawScore: raw, isCorrect: hits === total && wrong === 0, manualReviewRequired: false };
70	    }
71	    case 'numeric': {
72	      const val = answer.numericAnswer;
73	      if (val === undefined || val === null || !Number.isFinite(val) || question.correctNumeric === null) {
74	        return { questionId: question.id, rawScore: 0, isCorrect: false, manualReviewRequired: false };
75	      }
76	      const within = Math.abs(val - question.correctNumeric) <= question.numericTolerance;
77	      return { questionId: question.id, rawScore: within ? max : 0, isCorrect: within, manualReviewRequired: false };
78	    }
79	    case 'text':
80	      return { questionId: question.id, rawScore: 0, isCorrect: false, manualReviewRequired: true };
81	  }
82	}
83	
84	/** Round to nearest configured increment (default 0.5 — half-up). */
85	export function roundToIncrement(value: number, increment: number): number {
86	  if (!Number.isFinite(increment) || increment <= 0) return value;
87	  return Math.round(value / increment) * increment;
88	}
89	
90	/** Backwards-compatible 0.5-grid alias for callers that don't need configurability. */
91	export function roundToHalf(value: number): number {
92	  return roundToIncrement(value, 0.5);
93	}
94	
95	/** Validate a manual grade increment is on the configured grid and within bounds. */
96	export function isValidPartialScore(score: number, max: number, increment = 0.5): boolean {
97	  if (!Number.isFinite(score)) return false;
98	  if (score < 0 || score > max) return false;
99	  if (!Number.isFinite(increment) || increment <= 0) return true;
100	  const ratio = score / increment;
101	  return Math.abs(ratio - Math.round(ratio)) < 1e-9;
102	}
103	
104	/**
105	 * Apply the configured type weight. The map MUST contain a finite weight for
106	 * the supplied type — silent fallbacks are forbidden so that misconfigured
107	 * deployments fail loudly instead of producing distorted scores.
108	 */
109	export function applyTypeWeight(
110	  score: number,
111	  type: QuestionType,
112	  weights: Record<string, number>,
113	  increment = 0.5
114	): number {
115	  const w = weights[type];
116	  if (typeof w !== 'number' || !Number.isFinite(w)) {
117	    throw new Error(`Missing or invalid weight for question type '${type}'`);
118	  }
119	  return roundToIncrement(score * w, increment);
120	}
121	
122	export interface WeightedTotal {
123	  total: number;
124	  maxTotal: number;
125	}
126	
127	export function totalWeighted(
128	  results: { score: number; max: number; type: QuestionType }[],
129	  weights: Record<string, number>
130	): WeightedTotal {
131	  let total = 0;
132	  let maxTotal = 0;
133	  for (const r of results) {
134	    total += applyTypeWeight(r.score, r.type, weights);
135	    maxTotal += applyTypeWeight(r.max, r.type, weights);
136	  }
137	  return { total: roundToHalf(total), maxTotal: roundToHalf(maxTotal) };
138	}
139	
140	export function requiresSecondReview(firstScore: number, secondScore: number, deltaThreshold: number): boolean {
141	  return Math.abs(firstScore - secondScore) > deltaThreshold;
142	}
143	
