1	import {
2	  requiresSecondReview, roundToIncrement, applyTypeWeight
3	} from '@domain/grading/scoring';
4	import { encryptString, decryptString, type EncryptedField } from '@shared/crypto/fieldCrypto';
5	import { gradesRepository, DuplicateGradeError, type Grade } from '@persistence/gradesRepository';
6	import { attemptsRepository } from '@persistence/attemptsRepository';
7	import { questionsRepository } from '@persistence/questionsRepository';
8	import { businessConfig } from './businessConfig';
9	import { currentEncryptionKey } from './authService';
10	import { requireRole, requireSession } from './authorization';
11	import { uid } from '@shared/utils/id';
12	import { logger } from '@shared/logging/logger';
13	
14	export interface ManualGradeInput {
15	  attemptId: string;
16	  score: number;
17	  notes: string;
18	}
19	
20	export interface SecondReviewInput {
21	  score: number;
22	  notes: string;
23	}
24	
25	/** Raised when the active session cannot decrypt a notes payload (typically because it was written by a different reviewer). */
26	export class NotesDecryptionError extends Error {
27	  constructor() {
28	    super('Notes are encrypted with a different reviewer\'s key and cannot be decrypted in this session');
29	    this.name = 'NotesDecryptionError';
30	  }
31	}
32	
33	async function encryptNotes(notes: string): Promise<EncryptedField | null> {
34	  if (!notes) return null;
35	  const key = currentEncryptionKey();
36	  if (!key) throw new Error('No encryption key in session');
37	  return encryptString(key, notes);
38	}
39	
40	export async function decryptNotes(payload: EncryptedField | null): Promise<string> {
41	  if (!payload) return '';
42	  const key = currentEncryptionKey();
43	  if (!key) throw new NotesDecryptionError();
44	  try {
45	    return await decryptString(key, payload);
46	  } catch {
47	    // Wrong key (cross-user notes), corrupt payload, or any other AES failure.
48	    throw new NotesDecryptionError();
49	  }
50	}
51	
52	function gradingKnobs() {
53	  const cfg = businessConfig().grading;
54	  return {
55	    increment: cfg.partialIncrement,
56	    weights: cfg.weights,
57	    deltaThreshold: cfg.secondReviewDelta
58	  };
59	}
60	
61	/**
62	 * Read-only helper that lets the review UI (and the duplicate-guard inside
63	 * `submitFirstReview`) check whether any grader has already submitted a
64	 * grade for the given attempt — globally, not filtered by current grader.
65	 */
66	export async function findGradeByAttempt(attemptId: string): Promise<Grade | null> {
67	  requireSession();
68	  return (await gradesRepository.findByAttemptId(attemptId)) ?? null;
69	}
70	
71	/**
72	 * First review submission. Enforces the one-grade-per-attempt invariant at
73	 * the service boundary by explicitly probing the global index, and is
74	 * defended in depth by the unique IDB index on `attemptId` which surfaces
75	 * as `DuplicateGradeError` for any race that slipped past the probe.
76	 *
77	 * Workflow: the first review never finalizes a grade by itself when the
78	 * manual score deviates from the auto-graded baseline by more than the
79	 * configured threshold (default 10) — that grade is forced into
80	 * `PENDING_SECOND_REVIEW` and cannot become COMPLETED until a different
81	 * reviewer submits a second review. Manual-only question types (text) have
82	 * no auto baseline at all, so they ALWAYS transition to
83	 * `PENDING_SECOND_REVIEW`. Only first reviews where the score agrees with
84	 * the auto baseline within the threshold short-circuit to COMPLETED.
85	 */
86	export async function submitFirstReview(input: ManualGradeInput): Promise<Grade> {
87	  const { userId: grader } = requireRole('reviewer', 'administrator');
88	  const attempt = await attemptsRepository.get(input.attemptId);
89	  if (!attempt) throw new Error('Attempt not found');
90	  const question = await questionsRepository.get(attempt.questionId);
91	  if (!question) throw new Error('Question not found');
92	  if (!Number.isFinite(input.score) || input.score < 0 || input.score > question.maxScore) {
93	    throw new Error(`Score must be between 0 and ${question.maxScore}`);
94	  }
95	  // Service-level uniqueness probe.
96	  const existing = await gradesRepository.findByAttemptId(input.attemptId);
97	  if (existing) {
98	    logger.warn('grading.first.duplicate', { attemptId: input.attemptId, existingGradeId: existing.id, grader });
99	    throw new Error('A grade already exists for this attempt');
100	  }
101	
102	  const knobs = gradingKnobs();
103	  const rounded = roundToIncrement(input.score, knobs.increment);
104	  const weighted = applyTypeWeight(rounded, question.type, knobs.weights, knobs.increment);
105	  const notesEncrypted = await encryptNotes(input.notes);
106	
107	  // State-machine decision: does this first review need a mandatory
108	  // second review before it can finalize?
109	  const hasAutoBaseline = !attempt.needsManualGrading && attempt.autoScore !== null && Number.isFinite(attempt.autoScore);
110	  const baseline = hasAutoBaseline ? (attempt.autoScore as number) : null;
111	  const deltaExceeds = baseline === null
112	    ? true   // no baseline → always require a second reviewer
113	    : requiresSecondReview(rounded, baseline, knobs.deltaThreshold);
114	
115	  const state: 'PENDING_SECOND_REVIEW' | 'COMPLETED' = deltaExceeds ? 'PENDING_SECOND_REVIEW' : 'COMPLETED';
116	  const finalScoreOnFirst = state === 'COMPLETED' ? weighted : null;
117	  const blockedReason = deltaExceeds
118	    ? (baseline === null
119	        ? 'Pending second review: question requires manual grading (no auto baseline)'
120	        : `Pending second review: first-review score ${rounded} differs from auto baseline ${baseline} by more than ${knobs.deltaThreshold}`)
121	    : null;
122	
123	  const now = Date.now();
124	  const grade: Grade = {
125	    id: uid('grade'),
126	    attemptId: attempt.id,
127	    questionId: question.id,
128	    graderId: grader,
129	    firstScore: rounded,
130	    secondScore: null,
131	    secondGraderId: null,
132	    finalScore: finalScoreOnFirst,
133	    state,
134	    awaitingSecondReview: state === 'PENDING_SECOND_REVIEW',
135	    blockedReason,
136	    notesEncrypted,
137	    createdAt: now,
138	    updatedAt: now
139	  };
140	  try {
141	    await gradesRepository.put(grade);
142	  } catch (e) {
143	    if (e instanceof DuplicateGradeError) {
144	      logger.warn('grading.first.race', { attemptId: input.attemptId, grader });
145	      throw new Error('A grade already exists for this attempt');
146	    }
147	    throw e;
148	  }
149	  logger.info('grading.first', {
150	    gradeId: grade.id, attemptId: attempt.id, graderId: grader,
151	    questionType: question.type, firstScore: rounded,
152	    finalScore: grade.finalScore, state: grade.state
153	  });
154	  if (deltaExceeds) {
155	    logger.warn('grading.first.pending_second_review', {
156	      gradeId: grade.id, attemptId: attempt.id,
157	      firstScore: rounded, autoBaseline: baseline,
158	      threshold: knobs.deltaThreshold
159	    });
160	  }
161	  return grade;
162	}
163	
164	/**
165	 * Second review submission. Drives the grade from PENDING_SECOND_REVIEW to
166	 * COMPLETED. Refuses to operate on a grade that has already finalized
167	 * (state === COMPLETED) — the workflow is one-way and a grade cannot be
168	 * "re-completed". The final score is the type-weighted average of the two
169	 * reviewers' scores. A delta exceeding the configured threshold is recorded
170	 * in `blockedReason` for audit but does not block completion at this stage
171	 * — the mandatory second review IS the resolution.
172	 */
173	export async function submitSecondReview(gradeId: string, input: SecondReviewInput): Promise<Grade> {
174	  const { userId: grader } = requireRole('reviewer', 'administrator');
175	  const grade = await gradesRepository.get(gradeId);
176	  if (!grade) throw new Error('Grade not found');
177	  if (grade.state !== 'PENDING_SECOND_REVIEW') {
178	    logger.warn('grading.second.invalid_state', { gradeId, state: grade.state });
179	    throw new Error(`Grade is not awaiting a second review (state=${grade.state})`);
180	  }
181	  const question = await questionsRepository.get(grade.questionId);
182	  if (!question) throw new Error('Question not found');
183	  if (!Number.isFinite(input.score) || input.score < 0 || input.score > question.maxScore) {
184	    throw new Error(`Score must be between 0 and ${question.maxScore}`);
185	  }
186	  if (grader === grade.graderId) throw new Error('Second review must be by a different grader');
187	
188	  const knobs = gradingKnobs();
189	  const rounded = roundToIncrement(input.score, knobs.increment);
190	  const notesEncrypted = await encryptNotes(input.notes);
191	  const exceedsThreshold = requiresSecondReview(grade.firstScore, rounded, knobs.deltaThreshold);
192	
193	  if (exceedsThreshold) {
194	    logger.warn('grading.delta.exceeded', {
195	      gradeId, attemptId: grade.attemptId,
196	      firstScore: grade.firstScore, secondScore: rounded,
197	      delta: Math.abs(grade.firstScore - rounded), threshold: knobs.deltaThreshold
198	    });
199	  }
200	
201	  const avg = (grade.firstScore + rounded) / 2;
202	  const weightedFinal = applyTypeWeight(avg, question.type, knobs.weights, knobs.increment);
203	  const updated: Grade = {
204	    ...grade,
205	    secondScore: rounded,
206	    secondGraderId: grader,
207	    finalScore: weightedFinal,
208	    state: 'COMPLETED',
209	    awaitingSecondReview: false,
210	    blockedReason: exceedsThreshold
211	      ? `Audit: delta ${Math.abs(grade.firstScore - rounded)} exceeded threshold ${knobs.deltaThreshold}`
212	      : null,
213	    notesEncrypted: notesEncrypted ?? grade.notesEncrypted,
214	    updatedAt: Date.now()
215	  };
216	  await gradesRepository.put(updated);
217	  logger.info('grading.second', {
218	    gradeId, attemptId: grade.attemptId, secondGraderId: grader,
219	    secondScore: rounded, finalScore: weightedFinal,
220	    deltaExceeded: exceedsThreshold
221	  });
222	  return updated;
223	}
224	
225	/** A grade is complete once the workflow has reached the COMPLETED state. */
226	export function isComplete(grade: Grade): boolean {
227	  return grade.state === 'COMPLETED';
228	}
229	
230	/**
231	 * Reviewers and administrators see every grade in the system so they can
232	 * make informed decisions before submitting their own first review (no
233	 * blind spots). Other roles get an empty list.
234	 */
235	export async function listGrades(): Promise<Grade[]> {
236	  requireRole('reviewer', 'administrator');
237	  return gradesRepository.list();
238	}
