25	export function recommendFoods(
26	  prefs: DietaryPreferences,
27	  foods: FoodItem[],
28	  equivalents: Record<string, string>
29	): RecommendationResult {
30	  const budget = calculateNutritionBudget(prefs);
31	  const calorieCap = budget ? Math.round(budget.calories / 4) : Infinity; // ~per-meal cap
32	  const safe = foods.filter((f) => !f.allergens.some((a) => prefs.allergens.includes(a)) && !prefs.dislikes.includes(f.id));
33	  const items: Recommendation[] = [];
34	  for (const f of safe) {
35	    const reasons: string[] = [];
36	    let score = 0;
37	    if (prefs.goals.includes('high-protein') && f.tags.includes('high-protein')) {
38	      score += 2; reasons.push('Aligns with your high-protein goal');
39	    }
40	    if (prefs.goals.includes('whole-grain') && f.tags.includes('whole-grain')) {
41	      score += 2; reasons.push('Whole-grain choice');
42	    }
43	    if (prefs.goals.includes('weight-loss') && f.calories <= 200) {
44	      score += 1; reasons.push(`Lower calorie option (${f.calories} kcal)`);
45	    }
46	    if (prefs.goals.includes('dairy-free') && !f.allergens.includes('dairy')) {
47	      score += 1; reasons.push('Dairy-free');
48	    }
49	    if (prefs.goals.includes('low-sodium') && !f.tags.includes('high-sodium')) {
50	      score += 0.5;
51	    }
52	    if (budget && f.calories > calorieCap) {
53	      score -= 1; reasons.push(`Exceeds your per-meal calorie cap (~${calorieCap} kcal)`);
54	    } else if (budget) {
55	      reasons.push(`Fits within your daily ${budget.calories} kcal budget`);
56	    }
57	    if (reasons.length === 0) reasons.push('Within your dietary constraints');
58	    const swapId = equivalents[f.id];
59	    const swap = swapId ? foods.find((x) => x.id === swapId) ?? null : null;
60	    items.push({ food: f, score, reasons, swap });
61	  }
62	  items.sort((a, b) => b.score - a.score);
63	  return { budget, items };
64	}
65	
66	export function findEquivalent(foodId: string, foods: FoodItem[], equivalents: Record<string, string>): FoodItem | null {
67	  const swapId = equivalents[foodId];
68	  if (!swapId) return null;
69	  return foods.find((f) => f.id === swapId) ?? null;
70	}
