19	import { idbAll, idbPut, idbDelete } from '@persistence/indexedDb';
20	import { uid } from '@shared/utils/id';
21	
22	export type LogLevel = 'debug' | 'info' | 'warn' | 'error';
23	
24	export interface LogEntry {
25	  id: string;
26	  ts: number;
27	  level: LogLevel;
28	  event: string;
29	  context: Record<string, unknown>;
30	}
31	
32	const MAX_ENTRIES = 500;
33	const PRUNE_INTERVAL = 50;
34	
35	const SENSITIVE_KEYS = new Set<string>([
36	  'password', 'newPassword', 'oldPassword',
37	  'token', 'apiKey', 'secret',
38	  'notes', 'notesPlain', 'notesEncrypted',
39	  'encryptedPreferences', 'preferences',
40	  'hash', 'hashB64', 'salt', 'saltB64',
41	  'encryptionKey', 'cryptoKey'
42	]);
43	
44	function redact(context: Record<string, unknown>): Record<string, unknown> {
45	  const out: Record<string, unknown> = {};
46	  for (const [k, v] of Object.entries(context)) {
47	    if (SENSITIVE_KEYS.has(k)) {
48	      out[k] = '[REDACTED]';
49	    } else {
50	      out[k] = v;
51	    }
52	  }
53	  return out;
