56	const buffer: LogEntry[] = [];
57	const subscribers = new Set<(entry: LogEntry) => void>();
58	
59	let persistEnabled = true;
60	let writesSinceLastPrune = 0;
61	/** Single-writer chain so callers can `await flushLogs()` for determinism. */
62	let writeChain: Promise<void> = Promise.resolve();
63	
64	async function pruneIfNeeded(): Promise<void> {
65	  if (++writesSinceLastPrune < PRUNE_INTERVAL) return;
66	  writesSinceLastPrune = 0;
67	  try {
68	    const all = await idbAll<LogEntry>('logs');
69	    if (all.length <= MAX_ENTRIES) return;
70	    all.sort((a, b) => a.ts - b.ts);
71	    const excess = all.slice(0, all.length - MAX_ENTRIES);
72	    for (const e of excess) await idbDelete('logs', e.id);
73	  } catch { /* swallow — pruning is best-effort */ }
74	}
