76	async function persistEntry(entry: LogEntry): Promise<void> {
77	  if (!persistEnabled) return;
78	  try {
79	    await idbPut('logs', entry);
80	    await pruneIfNeeded();
81	  } catch { /* swallow — logger never throws */ }
