4	/**
5	 * Grade workflow state machine. A grade always starts in either
6	 * `PENDING_SECOND_REVIEW` (when the first review's score deviates from the
7	 * auto-graded baseline by more than the configured threshold, or when the
8	 * question type has no auto baseline at all) or `COMPLETED` (when the first
9	 * review is already in agreement with the auto-graded baseline). The only
10	 * legal transition is `PENDING_SECOND_REVIEW → COMPLETED` via
11	 * `submitSecondReview`.
12	 */
13	export type GradeState = 'PENDING_SECOND_REVIEW' | 'COMPLETED';
14	
15	export interface Grade {
16	  id: string;
17	  attemptId: string;
18	  questionId: string;
19	  graderId: string;
20	  /** First-pass score, on the configured grid. */
21	  firstScore: number;
22	  /** Second-review score, present once a second reviewer has acted. */
23	  secondScore: number | null;
24	  secondGraderId: string | null;
25	  /**
26	   * Final score policy: in `PENDING_SECOND_REVIEW` the final score is `null`
27	   * — the grade is not yet authoritative. Once the mandatory second review
28	   * has been recorded the grade transitions to `COMPLETED` and `finalScore`
29	   * holds the type-weighted average of `firstScore` and `secondScore`,
30	   * rounded to the configured increment. A grade in `COMPLETED` always has
31	   * a non-null `finalScore`.
32	   */
33	  finalScore: number | null;
34	  /** Workflow state — see GradeState. */
35	  state: GradeState;
36	  /** True while the grade is awaiting a second reviewer (mirror of state === PENDING_SECOND_REVIEW). */
37	  awaitingSecondReview: boolean;
38	  /** Free-form audit message (e.g. delta exceeded threshold). */
39	  blockedReason: string | null;
40	  /** Encrypted free-text grader notes. */
41	  notesEncrypted: EncryptedField | null;
42	  createdAt: number;
43	  updatedAt: number;
44	}
