46	/**
47	 * Persistence-layer enforcement: the IndexedDB store has a unique index on
48	 * `attemptId`, so two grades for the same attempt cannot coexist. Repository
49	 * helpers below propagate the underlying ConstraintError as a typed `put`
50	 * rejection so the service layer can map it to a friendly message.
51	 */
52	export class DuplicateGradeError extends Error {
53	  constructor(public readonly attemptId: string) {
54	    super(`A grade already exists for attempt ${attemptId}`);
55	    this.name = 'DuplicateGradeError';
56	  }
