129	 * sitting in a long quiet window would be prematurely exhausted and
130	 * dead-lettered before any reviewer ever saw it. Subscription drops
131	 * short-circuit immediately and also do not count as an attempt.
132	 */
133	async function processOne(messageId: string): Promise<void> {
134	  const cfg = businessConfig();
135	  const message = await messagesRepository.get(messageId);
136	  if (!message) return;
137	  if (message.status !== 'pending') return;
138	  if (message.nextAttemptAt > Date.now()) return;
139	
140	  const now = new Date();
141	
142	  // 1. Subscription drop — immediate, never counted as a delivery attempt.
143	  const prefs: SubscriptionPreferences = await messagesRepository.getSubscription(message.toUserId);
144	  if (prefs.unsubscribed.includes(message.category)) {
145	    const dropped: Message = {
146	      ...message,
147	      status: 'dead',
148	      lastError: `Recipient unsubscribed from ${message.category}`
149	    };
150	    await messagesRepository.put(dropped);
151	    await messagesRepository.pushDeadLetter(dropped);
152	    logger.warn('messaging.dropped', { messageId: message.id, reason: dropped.lastError });
153	    return;
154	  }
155	
156	  // 2. Quiet hours — DEFERRAL, not an attempt. attempts is preserved.
157	  const recipientQuiet: QuietHours | null = preferences.getQuietHours(message.toUserId);
158	  const quiet = recipientQuiet ?? cfg.quietHours;
159	  if (isWithinQuietHours(now, quiet)) {
160	    const until = nextQuietEnd(now, quiet).getTime();
161	    const deferred: Message = {
162	      ...message,
163	      // attempts intentionally unchanged
164	      nextAttemptAt: Math.max(until, backoffNextAttempt(now, message.attempts + 1, cfg.messaging.retryBackoffMs)),
165	      lastError: 'Quiet hours'
166	    };
167	    await messagesRepository.put(deferred);
168	    logger.info('messaging.deferred', {
169	      messageId: message.id, attempts: message.attempts, reason: 'Quiet hours', nextAttemptAt: deferred.nextAttemptAt
170	    });
171	    return;
172	  }
173	
174	  // 3. Rate limit — DEFERRAL, not an attempt. attempts is preserved.
175	  const consume = await messagingPolicyRepository.tryConsumeRate(
176	    message.toUserId,
177	    cfg.messaging.ratePerMinute,
178	    now.getTime()
179	  );
180	  if (!consume.ok) {
181	    const deferred: Message = {
182	      ...message,
183	      // attempts intentionally unchanged
184	      nextAttemptAt: Math.max(consume.nextAvailableAt, backoffNextAttempt(now, message.attempts + 1, cfg.messaging.retryBackoffMs)),
185	      lastError: 'Rate limit'
186	    };
187	    await messagesRepository.put(deferred);
188	    logger.info('messaging.deferred', {
189	      messageId: message.id, attempts: message.attempts, reason: 'Rate limit', nextAttemptAt: deferred.nextAttemptAt
190	    });
191	    return;
192	  }
193	
194	  // 4. Real delivery attempt — only NOW does the retry counter advance.
195	  const attemptsNow = message.attempts + 1;
196	  if (attemptsNow > cfg.messaging.maxAttempts) {
197	    const dead: Message = {
198	      ...message,
199	      attempts: attemptsNow,
200	      status: 'dead',
201	      lastError: `Exceeded ${cfg.messaging.maxAttempts} delivery attempts`
202	    };
203	    await messagesRepository.put(dead);
204	    await messagesRepository.pushDeadLetter(dead);
205	    logger.warn('messaging.dead_letter', { messageId: message.id, reason: dead.lastError, attempts: attemptsNow });
206	    return;
207	  }
208	
209	  try {
210	    const delivered: Message = {
211	      ...message,
212	      attempts: attemptsNow,
213	      status: 'delivered',
214	      deliveredAt: now.getTime(),
215	      lastError: null
216	    };
217	    await messagesRepository.put(delivered);
218	    logger.info('messaging.delivered', { messageId: message.id, attempts: attemptsNow });
219	  } catch (e) {
220	    // Real failure — bumped attempts is persisted with a backoff.
221	    const failed: Message = {
222	      ...message,
223	      attempts: attemptsNow,
224	      lastError: e instanceof Error ? e.message : 'Delivery failed',
225	      nextAttemptAt: backoffNextAttempt(now, attemptsNow, cfg.messaging.retryBackoffMs)
226	    };
227	    await messagesRepository.put(failed);
228	    logger.warn('messaging.deliver.failed', { messageId: message.id, attempts: attemptsNow, error: failed.lastError });
229	  }
230	}
