1	export interface QuietHours {
2	  startHour: number; // 0-23 inclusive
3	  endHour: number;   // 0-23 inclusive (window is [start, end))
4	}
5	
6	/**
7	 * Validate a quiet-hours window. Both endpoints must be integers in [0, 23]
8	 * and the window must not be zero-length (start === end is meaningless).
9	 */
10	export function isValidQuietHours(value: unknown): value is QuietHours {
11	  if (!value || typeof value !== 'object') return false;
12	  const v = value as Partial<QuietHours>;
13	  if (!Number.isInteger(v.startHour) || !Number.isInteger(v.endHour)) return false;
14	  const s = v.startHour as number;
15	  const e = v.endHour as number;
16	  if (s < 0 || s > 23 || e < 0 || e > 23) return false;
17	  if (s === e) return false;
18	  return true;
19	}
20	
21	export function isWithinQuietHours(date: Date, qh: QuietHours): boolean {
22	  const h = date.getHours();
23	  if (qh.startHour === qh.endHour) return false;
24	  if (qh.startHour < qh.endHour) return h >= qh.startHour && h < qh.endHour;
25	  // Crosses midnight: e.g. 21 → 7
26	  return h >= qh.startHour || h < qh.endHour;
27	}
28	
29	export function nextQuietEnd(date: Date, qh: QuietHours): Date {
30	  const out = new Date(date);
31	  out.setMinutes(0, 0, 0);
32	  while (isWithinQuietHours(out, qh)) {
33	    out.setHours(out.getHours() + 1);
34	  }
35	  return out;
36	}
