172	/**
173	 * Second review submission. Drives the grade from PENDING_SECOND_REVIEW to
174	 * COMPLETED. Refuses to operate on a grade that has already finalized
175	 * (state === COMPLETED) — the workflow is one-way and a grade cannot be
176	 * "re-completed". The final score is the type-weighted average of the two
177	 * reviewers' scores. A delta exceeding the configured threshold is recorded
178	 * in `blockedReason` for audit but does not block completion at this stage
179	 * — the mandatory second review IS the resolution.
180	 */
181	export async function submitSecondReview(gradeId: string, input: SecondReviewInput): Promise<Grade> {
182	  const { userId: grader } = requireRole('reviewer', 'administrator');
183	  const grade = await gradesRepository.get(gradeId);
184	  if (!grade) throw new Error('Grade not found');
185	  if (grade.state !== 'PENDING_SECOND_REVIEW') {
186	    logger.warn('grading.second.invalid_state', { gradeId, state: grade.state });
187	    throw new Error(`Grade is not awaiting a second review (state=${grade.state})`);
188	  }
189	  // State-machine guard: a grade in PENDING_SECOND_REVIEW must never carry
190	  // a finalized score; if it does, the persisted record is corrupt and the
191	  // workflow refuses to advance it. This catches tampering or schema drift.
192	  if (grade.finalScore !== null || grade.secondGraderId !== null) {
193	    logger.error('grading.second.corrupt_pending', { gradeId });
194	    throw new Error('Refusing to advance a corrupt PENDING_SECOND_REVIEW record');
195	  }
196	  const question = await questionsRepository.get(grade.questionId);
197	  if (!question) throw new Error('Question not found');
198	  if (!Number.isFinite(input.score) || input.score < 0 || input.score > question.maxScore) {
199	    throw new Error(`Score must be between 0 and ${question.maxScore}`);
200	  }
201	  if (grader === grade.graderId) throw new Error('Second review must be by a different grader');
202	
203	  const knobs = gradingKnobs();
204	  const rounded = roundToIncrement(input.score, knobs.increment);
205	  const notesEncrypted = await encryptNotes(input.notes);
206	  const exceedsThreshold = requiresSecondReview(grade.firstScore, rounded, knobs.deltaThreshold);
207	
208	  if (exceedsThreshold) {
209	    logger.warn('grading.delta.exceeded', {
210	      gradeId, attemptId: grade.attemptId,
211	      firstScore: grade.firstScore, secondScore: rounded,
212	      delta: Math.abs(grade.firstScore - rounded), threshold: knobs.deltaThreshold
213	    });
214	  }
215	
216	  const avg = (grade.firstScore + rounded) / 2;
217	  const weightedFinal = applyTypeWeight(avg, question.type, knobs.weights, knobs.increment);
218	  const updated: Grade = {
219	    ...grade,
220	    secondScore: rounded,
221	    secondGraderId: grader,
222	    finalScore: weightedFinal,
223	    state: 'COMPLETED',
224	    awaitingSecondReview: false,
225	    blockedReason: exceedsThreshold
226	      ? `Audit: delta ${Math.abs(grade.firstScore - rounded)} exceeded threshold ${knobs.deltaThreshold}`
227	      : null,
228	    notesEncrypted: notesEncrypted ?? grade.notesEncrypted,
229	    updatedAt: Date.now()
230	  };
231	  assertGradeStateInvariant(updated);
232	  await gradesRepository.put(updated);
233	  logger.info('grading.second', {
234	    gradeId, attemptId: grade.attemptId, secondGraderId: grader,
235	    secondScore: rounded, finalScore: weightedFinal,
236	    deltaExceeded: exceedsThreshold
237	  });
238	  return updated;
239	}
