{"replace_all": false, "file_path": "/home/mint/Desktop/projects/task-09/repo/src/ui/routes/Review.svelte", "old_string": "  async function submitSecond(): Promise<void> {
    if (!working || !working.grade) return;
    error = '';
    try {
      await submitSecondReview(working.grade.id, { score: scoreInput, notes: notesInput });
      await reload();
      working = null;
